// ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ Trabajadores (usuarios app + externo) ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬
async function getTrabajadores(request, env) {
  const { empresa_id, obra_id: obraAuth, isSuperadmin, isEmpresaAdmin, isAdmin, rol } = await getAuth(request, env);
  if (!empresa_id) return err('No autorizado', 403);
  const url = new URL(request.url);
  const obra_id = url.searchParams.get('obra_id') || ((!isSuperadmin && !isEmpresaAdmin && !isAdmin) ? obraAuth : null);

  let sqlU = 'SELECT id, nombre, rol, departamento, obra_id, NULL as dni, "app" as tipo, foto_r2_key, CASE WHEN telegram_id IS NOT NULL THEN 1 ELSE 0 END as tiene_telegram FROM usuarios WHERE empresa_id=? AND activo=1';
  const paramsU = [empresa_id];
  if (obra_id) { sqlU += ' AND obra_id=?'; paramsU.push(parseInt(obra_id)); }
  sqlU += ' ORDER BY nombre';

  let sqlP = 'SELECT id, nombre, NULL as rol, departamento, obra_id, dni, "externo" as tipo, foto_r2_key, 0 as tiene_telegram FROM personal_externo WHERE empresa_id=? AND activo=1';
  const paramsP = [empresa_id];
  if (obra_id) { sqlP += ' AND obra_id=?'; paramsP.push(parseInt(obra_id)); }
  sqlP += ' ORDER BY nombre';

  const [ru, rp] = await Promise.all([
    env.DB.prepare(sqlU).bind(...paramsU).all(),
    env.DB.prepare(sqlP).bind(...paramsP).all(),
  ]);
  return json([...ru.results, ...rp.results]);
}

// ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ EPIs asignados (NEW-23) ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬ГғВў"ГўвҖҡВ¬
