async function cierreAutomaticoJornada(env) {
  try {
    const hoy = new Date().toLocaleDateString('en-CA', { timeZone: 'Europe/Madrid' }); // YYYY-MM-DD
    // Fichajes con hora_entrada pero sin hora_salida
    const { results: abiertos } = await env.DB.prepare(
      `SELECT f.*, ho.hora_salida as horario_salida, ho.horas_dia as horario_horas_dia
       FROM fichajes f
       LEFT JOIN horarios_obra ho ON f.obra_id = ho.obra_id AND f.empresa_id = ho.empresa_id
       WHERE f.fecha = ? AND f.hora_entrada IS NOT NULL AND f.hora_entrada != ''
         AND (f.hora_salida IS NULL OR f.hora_salida = '')`
    ).bind(hoy).all();

    if (!abiertos.length) return;

    let cerrados = 0;
    for (const f of abiertos) {
      const horaSalida = f.horario_salida || '18:00';
      const horas = calcHoras(f.hora_entrada, horaSalida);
      const horas_extra = f.horario_horas_dia ? Math.max(0, Math.round((horas - f.horario_horas_dia)*100)/100) : 0;
      const notasActual = f.notas ? f.notas + ' | ' : '';
      await env.DB.prepare(
        `UPDATE fichajes SET hora_salida=?, horas_trabajadas=?, horas_extra=?, notas=? WHERE id=?`
      ).bind(horaSalida, horas, horas_extra, notasActual + 'ГғВўГғвҖҡГӮВҸГӮВ° Cierre automГғВЎtico', f.id).run();
      cerrados++;
    }

    if (cerrados > 0) {
      await sendTelegram(env,
        `ГғВўГғвҖҡГӮВҸГӮВ° <b>Cierre automГғВЎtico de jornada</b>\nГ°ЕёвҖңвҖҰ ${hoy}\nГўЕ“вҖҰ ${cerrados} fichaje${cerrados > 1 ? 's cerrados' : ' cerrado'} automГғВЎticamente con hora del horario de obra.`
      );
    }
  } catch (e) {
    console.error('Error cierre automГғВЎtico jornada:', e.message);
  }
}

// ГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗГғВўГўвӮ¬ВўГғвҖҡГӮВҗ
