async function informeSemanal(empresa_id, empresa_nombre, env) {
  try {
    // Rango: semana anterior completa (lunesГўвӮ¬вҖқdomingo)
    const hoy  = new Date();
    const dow   = hoy.getDay(); // 0=dom ГўвӮ¬ВҰ 6=sГғВЎb
    const diasDesdeL = dow === 0 ? 6 : dow - 1;
    const lunesEsta  = new Date(hoy); lunesEsta.setDate(hoy.getDate() - diasDesdeL);
    const lunesAnt   = new Date(lunesEsta); lunesAnt.setDate(lunesEsta.getDate() - 7);
    const domAnt     = new Date(lunesAnt);  domAnt.setDate(lunesAnt.getDate() + 6);
    const desde = lunesAnt.toISOString().slice(0,10);
    const hasta = domAnt.toISOString().slice(0,10);

    // 1. Fichajes semana pasada
    const { results: fichajes } = await env.DB.prepare(
      `SELECT COUNT(*) as total,
              SUM(CASE WHEN horas_trabajadas > 0 THEN horas_trabajadas ELSE 0 END) as horas,
              SUM(CASE WHEN minutos_retraso > 0 THEN minutos_retraso ELSE 0 END) as min_retraso
       FROM fichajes WHERE empresa_id = ? AND fecha >= ? AND fecha <= ?`
    ).bind(empresa_id, desde, hasta).all();
    const fich = fichajes?.[0] || {};
    const horasTotStr = fich.horas ? `${fich.horas.toFixed(1)}h` : '0h';
    const retrasoStr  = fich.min_retraso ? ` (ГғВўГғвҖҡГӮВҸГӮВұ ${Math.round(fich.min_retraso)} min retraso acum.)` : '';

    // 2. Herramientas fuera (asignadas)
    const { results: herrFuera } = await env.DB.prepare(
      `SELECT COUNT(*) as total FROM herramientas WHERE empresa_id = ? AND estado = 'fuera'`
    ).bind(empresa_id).all();
    const nHerrFuera = herrFuera?.[0]?.total || 0;

    // 3. Equipos en mantenimiento/averiados
    const [pempMant, carrMant] = await Promise.all([
      env.DB.prepare(`SELECT COUNT(*) as total FROM pemp WHERE empresa_id = ? AND estado IN ('Mantenimiento','Averiada')`).bind(empresa_id).all(),
      env.DB.prepare(`SELECT COUNT(*) as total FROM carretillas WHERE empresa_id = ? AND estado IN ('Mantenimiento','Averiada')`).bind(empresa_id).all(),
    ]);
    const nEquiposMant = (pempMant.results?.[0]?.total || 0) + (carrMant.results?.[0]?.total || 0);

    // 4. Incidencias abiertas
    const { results: incAb } = await env.DB.prepare(
      `SELECT COUNT(*) as total FROM incidencias WHERE empresa_id = ? AND estado != 'resuelta'`
    ).bind(empresa_id).all();
    const nIncAb = incAb?.[0]?.total || 0;

    // 5. Pedidos pendientes
    const { results: pedPend } = await env.DB.prepare(
      `SELECT COUNT(*) as total FROM pedidos WHERE empresa_id = ? AND estado = 'pendiente'`
    ).bind(empresa_id).all();
    const nPedPend = pedPend?.[0]?.total || 0;

    // 6. Stock bajo (bobinas + tipos_cable + tipos_herramienta + inventario_seg)
    let stockBajo = 0;
    try {
      const [sc, sh, ss] = await Promise.all([
        env.DB.prepare(`SELECT COUNT(*) as c FROM tipos_cable tc
          JOIN bobinas b ON b.tipo_cable = tc.nombre AND b.empresa_id = ?
          WHERE tc.stock_minimo > 0 GROUP BY tc.id HAVING COUNT(b.codigo) < tc.stock_minimo`).bind(empresa_id).all(),
        env.DB.prepare(`SELECT COUNT(*) as c FROM tipos_herramienta th
          WHERE th.empresa_id = ? AND th.stock_minimo > 0
          AND (SELECT COUNT(*) FROM herramientas h WHERE h.tipo_id = th.id AND h.empresa_id = ? AND h.estado = 'disponible') < th.stock_minimo`).bind(empresa_id, empresa_id).all(),
        env.DB.prepare(`SELECT COUNT(*) as c FROM inventario_seg WHERE empresa_id = ? AND stock_minimo > 0 AND cantidad_disponible < stock_minimo AND estado != 'baja'`).bind(empresa_id).all(),
      ]);
      stockBajo = (sc.results?.length || 0) + (sh.results?.length || 0) + (ss.results?.[0]?.c || 0);
    } catch {}

    // 7. Tareas de obra pendientes / vencidas
    let nTareasPend = 0; let nTareasVenc = 0;
    try {
      const hoyStr = hoy.toISOString().slice(0,10);
      const [tp, tv] = await Promise.all([
        env.DB.prepare(`SELECT COUNT(*) as n FROM tareas_obra WHERE empresa_id=? AND estado NOT IN ('completada','bloqueada')`).bind(empresa_id).first().catch(()=>({n:0})),
        env.DB.prepare(`SELECT COUNT(*) as n FROM tareas_obra WHERE empresa_id=? AND estado NOT IN ('completada','bloqueada') AND fecha_limite < ?`).bind(empresa_id, hoyStr).first().catch(()=>({n:0})),
      ]);
      nTareasPend = tp?.n || 0;
      nTareasVenc = tv?.n || 0;
    } catch {}

    // 8. RFIs pendientes de respuesta
    let nRfisOpen = 0;
    try {
      const rv = await env.DB.prepare(
        `SELECT COUNT(*) as n FROM rfis WHERE empresa_id=? AND estado IN ('abierta','en_revision')`
      ).bind(empresa_id).first().catch(()=>({n:0}));
      nRfisOpen = rv?.n || 0;
    } catch {}

    // 9. Presupuesto ГўвӮ¬вҖқ desviaciГғВіn acumulada
    let presupuestoStr = '';
    try {
      const pres = await env.DB.prepare(
        `SELECT COALESCE(SUM(importe_previsto),0) as prev, COALESCE(SUM(importe_real),0) as real FROM presupuesto_obra WHERE empresa_id=?`
      ).bind(empresa_id).first().catch(()=>null);
      if (pres && pres.prev > 0) {
        const desv = pres.real - pres.prev;
        const desvPct = ((desv / pres.prev) * 100).toFixed(1);
        const desvSign = desv > 0 ? '+' : '';
        presupuestoStr = `Г°ЕёвҖҷВ¶ <b>Presupuesto:</b> ${pres.real.toLocaleString('es-ES')}ГўвҖҡВ¬ / ${pres.prev.toLocaleString('es-ES')}ГўвҖҡВ¬ previsto (${desvSign}${desvPct}%)\n`;
      }
    } catch {}

    // 10. Control de calidad ГўвӮ¬вҖқ deficiencias abiertas y resueltas en la semana
    let calidadStr = '';
    try {
      const [defAbiertas, defResueltas] = await Promise.all([
        env.DB.prepare(`SELECT COUNT(*) as n FROM control_calidad WHERE empresa_id=? AND estado IN ('abierto','en_reparacion')`).bind(empresa_id).first().catch(()=>({n:0})),
        env.DB.prepare(`SELECT COUNT(*) as n FROM control_calidad WHERE empresa_id=? AND estado IN ('resuelto','verificado') AND fecha_resolucion >= ?`).bind(empresa_id, desde).first().catch(()=>({n:0})),
      ]);
      const nAb = defAbiertas?.n || 0;
      const nRes = defResueltas?.n || 0;
      if (nAb > 0 || nRes > 0) {
        calidadStr = `Г°ЕёвҖқВҚ <b>Control calidad:</b> ${nAb} abierta${nAb!==1?'s':''} ГӮВ· ${nRes} resuelta${nRes!==1?'s':''} esta semana\n`;
      }
    } catch {}

    // ComposiciГғВіn del mensaje
    const semStr = `${desde} al ${hasta}`;
    let msg = `Г°ЕёвҖңЕ  <b>Informe semanal ГўвӮ¬вҖқ ${empresa_nombre}</b>\n`;
    msg += `<i>Semana: ${semStr}</i>\n\n`;
    msg += `Г°ЕёвҖҳВ· <b>Fichajes:</b> ${fich.total || 0} registros ГӮВ· ${horasTotStr}${retrasoStr}\n`;
    msg += `Г°ЕёВҸвҖ”ГҜВёВҸ <b>Equipos sin servicio:</b> ${nEquiposMant}\n`;
    msg += `Г°ЕёвҖәВ  <b>Herramientas fuera:</b> ${nHerrFuera}\n`;
    msg += `Г°ЕёвҖңВҰ <b>Pedidos pendientes:</b> ${nPedPend}\n`;
    msg += `Г°ЕёЕЎВЁ <b>Incidencias abiertas:</b> ${nIncAb}\n`;
    if (stockBajo > 0)    msg += `ГўЕЎВ ГҜВёВҸ <b>Alertas de stock:</b> ${stockBajo} bajo mГғВӯnimo\n`;
    if (nTareasPend > 0)  msg += `ГўЕ“вҖҰ <b>Tareas activas:</b> ${nTareasPend}${nTareasVenc > 0 ? ` (ГўЕЎВ ГҜВёВҸ ${nTareasVenc} VENCIDAS)` : ''}\n`;
    if (nRfisOpen > 0)    msg += `Г°ЕёвҖңвҖ№ <b>RFIs sin respuesta:</b> ${nRfisOpen}\n`;
    if (calidadStr)       msg += calidadStr;
    if (presupuestoStr)   msg += presupuestoStr;
    msg += `\n<i>Generado automГғВЎticamente por Alejandra App</i>`;

    await sendTelegram(env, msg);
  } catch(e) {
    console.error('informeSemanal error:', e.message);
  }
}

// ГўвҖқвӮ¬ГўвҖқвӮ¬ PULSO DIARIO ГўвӮ¬вҖқ comparaciГғВіn automГғВЎtica hoy vs ayer, coste mГғВӯnimo (~2 queries) ГўвҖқвӮ¬ГўвҖқвӮ¬
async function dailyPulse(env) {
  try {
    const devChatId = env.DEV_CHAT_ID;
    if (!devChatId) return;

    // Recoger mГғВ©tricas de hoy y ayer en paralelo
    const [
      fichajesHoy, fichajesAyer,
      erroresHoy, erroresAyer,
      incidenciasHoy, incidenciasAyer,
      usersHoy, usersAyer,
      sugsPendientes
    ] = await Promise.all([
      env.DB.prepare("SELECT COUNT(*) as n FROM fichajes WHERE fecha = date('now')").first().catch(() => ({ n: 0 })),
      env.DB.prepare("SELECT COUNT(*) as n FROM fichajes WHERE fecha = date('now', '-1 day')").first().catch(() => ({ n: 0 })),
      env.DB.prepare("SELECT COUNT(*) as n FROM logs WHERE nivel='error' AND created_at > datetime('now', '-24 hours')").first().catch(() => ({ n: 0 })),
      env.DB.prepare("SELECT COUNT(*) as n FROM logs WHERE nivel='error' AND created_at > datetime('now', '-48 hours') AND created_at <= datetime('now', '-24 hours')").first().catch(() => ({ n: 0 })),
      env.DB.prepare("SELECT COUNT(*) as n FROM incidencias WHERE created_at > datetime('now', '-24 hours')").first().catch(() => ({ n: 0 })),
      env.DB.prepare("SELECT COUNT(*) as n FROM incidencias WHERE created_at > datetime('now', '-48 hours') AND created_at <= datetime('now', '-24 hours')").first().catch(() => ({ n: 0 })),
      env.DB.prepare("SELECT COUNT(DISTINCT usuario_id) as n FROM sesiones WHERE last_used > datetime('now', '-24 hours')").first().catch(() => ({ n: 0 })),
      env.DB.prepare("SELECT COUNT(DISTINCT usuario_id) as n FROM sesiones WHERE last_used > datetime('now', '-48 hours') AND last_used <= datetime('now', '-24 hours')").first().catch(() => ({ n: 0 })),
      env.DB.prepare("SELECT COUNT(*) as n FROM sugerencias WHERE estado='pendiente' AND leida=0").first().catch(() => ({ n: 0 })),
    ]);

    const arrow = (curr, prev) => {
      if (!prev || prev === 0) return curr > 0 ? 'Г°ЕёвҖ вҖў' : 'ГўвӮ¬вҖқ';
      const pct = Math.round(((curr - prev) / prev) * 100);
      if (pct > 20) return `Г°ЕёвҖңЛҶ +${pct}%`;
      if (pct < -20) return `Г°ЕёвҖңвҖ° ${pct}%`;
      return `ГўЕҫВЎГҜВёВҸ ${pct >= 0 ? '+' : ''}${pct}%`;
    };

    // Detectar anomalГғВӯas
    const anomalias = [];
    if ((erroresHoy.n || 0) > (erroresAyer.n || 0) * 2 && erroresHoy.n >= 5)
      anomalias.push(`Г°ЕёвҖқВҙ Errores duplicados vs ayer (${erroresHoy.n} vs ${erroresAyer.n})`);
    if ((fichajesHoy.n || 0) < (fichajesAyer.n || 0) * 0.5 && fichajesAyer.n >= 5)
      anomalias.push(`ГўЕЎВ ГҜВёВҸ Fichajes muy por debajo de ayer (${fichajesHoy.n} vs ${fichajesAyer.n})`);
    if ((incidenciasHoy.n || 0) > 5)
      anomalias.push(`ГўЕЎВ ГҜВёВҸ ${incidenciasHoy.n} incidencias nuevas en 24h`);

    const fecha = new Date().toLocaleDateString('es-ES', { timeZone: 'Europe/Madrid', weekday: 'long', day: 'numeric', month: 'long' });
    let msg = `Г°ЕёвҖңЕ  <b>Pulso diario</b> ГўвӮ¬вҖқ ${fecha}\n\n`;
    msg += `Г°ЕёвҖҳВҘ Usuarios activos: <b>${usersHoy.n || 0}</b> ${arrow(usersHoy.n, usersAyer.n)}\n`;
    msg += `ГўВҸВ° Fichajes: <b>${fichajesHoy.n || 0}</b> ${arrow(fichajesHoy.n, fichajesAyer.n)}\n`;
    msg += `Г°ЕёвҖқВҙ Errores 24h: <b>${erroresHoy.n || 0}</b> ${arrow(erroresHoy.n, erroresAyer.n)}\n`;
    msg += `Г°ЕёЕЎВЁ Incidencias: <b>${incidenciasHoy.n || 0}</b> ${arrow(incidenciasHoy.n, incidenciasAyer.n)}\n`;
    if (sugsPendientes.n > 0) msg += `\nГ°ЕёвҖҷВ¬ ${sugsPendientes.n} sugerencia(s) pendiente(s)`;

    if (anomalias.length > 0) {
      msg += `\n\n<b>ГўЕЎВЎ AnomalГғВӯas:</b>\n` + anomalias.join('\n');
    } else {
      msg += `\n\nГўЕ“вҖҰ Sin anomalГғВӯas ГўвӮ¬вҖқ todo en orden`;
    }

    await sendTelegramToChat(env, devChatId, msg);
  } catch (e) {
    console.error('dailyPulse error:', e.message);
  }
}

// ГўвҖқвӮ¬ГўвҖқвӮ¬ BRIEFING MATUTINO ГўвӮ¬вҖқ enviado a encargados con Telegram a las 7am ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬
// Genera un resumen personalizado por obra para cada encargado / jefe_de_obra
// que tenga telegram_id configurado.
async function briefingMatutino(env) {
  try {
    const hoy = new Date().toISOString().slice(0, 10);
    // Encargados y jefes de obra con telegram_id y obra asignada
    const { results: encargados } = await env.DB.prepare(
      `SELECT u.id, u.nombre, u.telegram_id, u.obra_id, u.empresa_id, o.nombre as obra_nombre
       FROM usuarios u
       LEFT JOIN obras o ON o.id = u.obra_id
       WHERE u.activo = 1 AND u.telegram_id IS NOT NULL AND u.telegram_id != ''
         AND u.rol IN ('encargado','jefe_de_obra') AND u.obra_id IS NOT NULL`
    ).all().catch(() => ({ results: [] }));

    for (const enc of (encargados || [])) {
      try {
        const eid    = enc.empresa_id;
        const obraId = enc.obra_id;

        // Datos en paralelo
        const [fichHoy, tareasUrg, rfisOpen, incAbiertas, proximoEv, defUrg] = await Promise.all([
          env.DB.prepare(`SELECT COUNT(*) as n FROM fichajes WHERE empresa_id=? AND obra_id=? AND fecha=?`).bind(eid,obraId,hoy).first().catch(()=>({n:0})),
          env.DB.prepare(`SELECT titulo,prioridad,asignado_a,fecha_limite FROM tareas_obra WHERE empresa_id=? AND obra_id=? AND estado NOT IN ('completada','bloqueada') AND prioridad IN ('urgente','alta') ORDER BY CASE prioridad WHEN 'urgente' THEN 0 ELSE 1 END LIMIT 5`).bind(eid,obraId).all().catch(()=>({results:[]})),
          env.DB.prepare(`SELECT numero,titulo,prioridad FROM rfis WHERE empresa_id=? AND obra_id=? AND estado IN ('abierta','en_revision') ORDER BY CASE prioridad WHEN 'urgente' THEN 0 WHEN 'alta' THEN 1 WHEN 'normal' THEN 2 ELSE 3 END LIMIT 3`).bind(eid,obraId).all().catch(()=>({results:[]})),
          env.DB.prepare(`SELECT COUNT(*) as n FROM incidencias WHERE empresa_id=? AND obra_id=? AND estado IN ('abierta','en_progreso')`).bind(eid,obraId).first().catch(()=>({n:0})),
          env.DB.prepare(`SELECT titulo,fecha,tipo FROM eventos_calendario WHERE empresa_id=? AND (obra_id=? OR obra_id IS NULL) AND fecha >= ? ORDER BY fecha ASC LIMIT 2`).bind(eid,obraId,hoy).all().catch(()=>({results:[]})),
          env.DB.prepare(`SELECT COUNT(*) as total, COUNT(CASE WHEN prioridad='urgente' THEN 1 END) as urgentes FROM control_calidad WHERE empresa_id=? AND obra_id=? AND estado IN ('abierto','en_reparacion')`).bind(eid,obraId).first().catch(()=>({total:0,urgentes:0})),
        ]);

        const priIcon = { urgente:'Г°ЕёвҖқВҙ', alta:'Г°ЕёЕёВ ', normal:'Г°ЕёЕёВЎ', baja:'Г°ЕёЕёВў' };

        let msg = `ГўЛңвӮ¬ГҜВёВҸ <b>Buenos dГғВӯas, ${enc.nombre}!</b>\n`;
        msg += `Г°ЕёВҸвҖ” <b>${enc.obra_nombre||'Tu obra'}</b> ГўвӮ¬вҖқ ${hoy}\n`;
        msg += `ГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒГўвҖқВҒ\n\n`;

        msg += `Г°ЕёвҖҳВ· <b>Personal hoy:</b> ${fichHoy?.n||0} fichajes hasta ahora\n`;
        msg += `Г°ЕёЕЎВЁ <b>Incidencias abiertas:</b> ${incAbiertas?.n||0}\n`;

        const tRes = tareasUrg.results || [];
        if (tRes.length) {
          msg += `\nГўЕ“вҖҰ <b>Tareas urgentes/altas (${tRes.length}):</b>\n`;
          const hoyStr = hoy;
          tRes.forEach(t => {
            const venc = t.fecha_limite && t.fecha_limite < hoyStr ? 'ГўЕЎВ ГҜВёВҸ VENCIDA ' : '';
            msg += `  ${priIcon[t.prioridad]||'ГўЕЎВӘ'} ${t.titulo}${t.asignado_a?' ['+t.asignado_a+']':''}${venc?'\n     '+venc:''}\n`;
          });
        }

        const rRes = rfisOpen.results || [];
        if (rRes.length) {
          msg += `\nГ°ЕёвҖңвҖ№ <b>RFIs sin respuesta (${rRes.length}):</b>\n`;
          rRes.forEach(r2 => {
            msg += `  ${priIcon[r2.prioridad]||'Г°ЕёЕёВЎ'} ${r2.numero||'RFI'} ${r2.titulo}\n`;
          });
        }

        const defTotal = defUrg?.total || 0;
        const defUrgCount = defUrg?.urgentes || 0;
        if (defTotal > 0) {
          msg += `Г°ЕёвҖқВҚ <b>Deficiencias abiertas:</b> ${defTotal}${defUrgCount > 0 ? ` ГўвӮ¬вҖқ Г°ЕёвҖқВҙ ${defUrgCount} URGENTES` : ''}\n`;
        }

        const evs = proximoEv.results || [];
        if (evs.length) {
          msg += `\nГ°ЕёвҖңвҖҰ <b>PrГғВіximos eventos:</b>\n`;
          evs.forEach(ev => msg += `  ГўвӮ¬Вў ${ev.titulo} (${ev.fecha})\n`);
        }

        if (!tRes.length && !rRes.length && (incAbiertas?.n||0) === 0 && defTotal === 0) {
          msg += `\nГўЕ“вҖҰ <b>ГӮВЎTodo en orden! Sin pendientes urgentes.</b>`;
        }

        msg += `\n\n<i>ГўвӮ¬вҖқ Alejandra App | Responde a este mensaje para chatear</i>`;
        await sendTelegramToChat(env, enc.telegram_id, msg);

      } catch(eInner) {
        console.error(`briefingMatutino error para ${enc.nombre}: ${eInner.message}`);
      }
    }
  } catch(e) {
    console.error('briefingMatutino error:', e.message);
  }
}

async function alertasDiarias(env) {
  try {
    const hoy = new Date();

    // 0-prev. Limpiar tokens caducados (reset_tokens y vincular_tokens)
    try {
      await env.DB.prepare("DELETE FROM reset_tokens WHERE expires_at < datetime('now')").run();
      await env.DB.prepare("DELETE FROM vincular_tokens WHERE expires_at < datetime('now')").run();
    } catch(e) { console.error('cleanup tokens error:', e.message); }

    // 0. Informe semanal ГўвӮ¬вҖқ para cada empresa que lo tenga activado en el dГғВӯa de hoy
    const DIAS_ES = { 'lunes':1,'martes':2,'miГғВ©rcoles':3,'miercoles':3,'jueves':4,'viernes':5,'sГғВЎbado':6,'sabado':6,'domingo':0 };
    const dowHoy  = hoy.getDay(); // 0=dom ГўвӮ¬ВҰ 6=sГғВЎb
    try {
      const { results: empresasInf } = await env.DB.prepare(
        `SELECT id, nombre, informe_dia FROM empresas WHERE informe_semanal = 1 AND activa = 1`
      ).all();
      for (const emp of (empresasInf || [])) {
        const diaNum = DIAS_ES[( emp.informe_dia || 'lunes').toLowerCase()] ?? 1;
        if (diaNum === dowHoy) {
          await informeSemanal(emp.id, emp.nombre, env);
        }
      }
    } catch(e) { console.error('informeSemanal check error:', e.message); }

    // UX-06: obtener todas las empresas activas para filtrar alertas por empresa
    // (antes las queries mezclaban datos de TODAS las empresas sin indicar cuГғВЎl)
    const { results: empresasActivas } = await env.DB.prepare(
      `SELECT id, nombre FROM empresas WHERE activa = 1`
    ).all().catch(() => ({ results: [] }));
    const empMap = {};
    for (const e of (empresasActivas || [])) empMap[e.id] = e.nombre;
    const empLabel = (eid) => empMap[eid] ? ` [${empMap[eid]}]` : '';

    // 1. MГғВЎquinas averiadas hace mГғВЎs de 3 dГғВӯas sin reparar
    const [avPemp, avCarr] = await Promise.all([
      env.DB.prepare(`SELECT matricula, fecha_averia, obra_id, empresa_id FROM pemp WHERE estado = 'Averiada' AND fecha_averia IS NOT NULL`).all(),
      env.DB.prepare(`SELECT matricula, fecha_averia, obra_id, empresa_id FROM carretillas WHERE estado = 'Averiada' AND fecha_averia IS NOT NULL`).all(),
    ]);

    const DIAS_AVERIA = 3;
    const averiadas = [];
    for (const m of [...(avPemp.results||[]), ...(avCarr.results||[])]) {
      const dias = Math.floor((hoy - new Date(m.fecha_averia)) / 86400000);
      if (dias >= DIAS_AVERIA) averiadas.push(`Г°ЕёвҖңвҖ“ ${m.matricula}${empLabel(m.empresa_id)} ГўвӮ¬вҖқ ${dias} dГғВӯas averiada`);
    }
    if (averiadas.length) {
      await sendTelegram(env,
        `ГўЕЎВ ГҜВёВҸ <b>MГғВЎquinas averiadas sin reparar (ГғВўГўвӮ¬В°ГӮВҘ${DIAS_AVERIA} dГғВӯas)</b>\n\n` + averiadas.join('\n')
      );
    }

    // 2. Revisiones prГғВіximas ГўвӮ¬вҖқ usa dias_aviso_mant por equipo (default 15) cuando aviso_mantenimiento=1
    const DIAS_AVISO_DEFAULT = 15;
    const maxLimite = new Date(hoy); maxLimite.setDate(maxLimite.getDate() + 365); // ventana amplia
    const maxLimiteStr = maxLimite.toISOString().slice(0, 10);

    const [revPemp, revCarr] = await Promise.all([
      env.DB.prepare(`SELECT matricula, fecha_proxima_revision, aviso_mantenimiento, dias_aviso_mant, empresa_id FROM pemp WHERE fecha_proxima_revision IS NOT NULL AND fecha_proxima_revision != '' AND fecha_proxima_revision <= ?`).bind(maxLimiteStr).all(),
      env.DB.prepare(`SELECT matricula, fecha_proxima_revision, aviso_mantenimiento, dias_aviso_mant, empresa_id FROM carretillas WHERE fecha_proxima_revision IS NOT NULL AND fecha_proxima_revision != '' AND fecha_proxima_revision <= ?`).bind(maxLimiteStr).all(),
    ]);

    const revisiones = [];
    for (const m of [...(revPemp.results||[]), ...(revCarr.results||[])]) {
      const aviso = m.aviso_mantenimiento !== undefined ? m.aviso_mantenimiento : 1;
      if (!aviso) continue;
      const diasAviso = m.dias_aviso_mant || DIAS_AVISO_DEFAULT;
      const dias = Math.floor((new Date(m.fecha_proxima_revision) - hoy) / 86400000);
      if (dias < 0) revisiones.push(`Г°ЕёвҖңвҖ“ ${m.matricula}${empLabel(m.empresa_id)} ГўвӮ¬вҖқ VENCIDA hace ${Math.abs(dias)} dГғВӯas`);
      else if (dias <= diasAviso) revisiones.push(`Г°ЕёвҖңвҖ“ ${m.matricula}${empLabel(m.empresa_id)} ГўвӮ¬вҖқ vence en ${dias} dГғВӯas (${m.fecha_proxima_revision})`);
    }
    if (revisiones.length) {
      await sendTelegram(env,
        `Г°ЕёвҖңвҖҰ <b>Revisiones prГғВіximas o vencidas</b>\n\n` + revisiones.join('\n')
      );
    }

    // 3. Material Seguridad con caducidad prГғВіxima o vencida
    const DIAS_CAD = 30;
    const limiteCad = new Date(hoy); limiteCad.setDate(limiteCad.getDate() + DIAS_CAD);
    const limiteCadStr = limiteCad.toISOString().slice(0, 10);
    const matCad = await env.DB.prepare(
      `SELECT tipo_material, codigo, nombre, fecha_caducidad, empresa_id FROM inventario_seg
       WHERE fecha_caducidad IS NOT NULL AND fecha_caducidad != '' AND fecha_caducidad <= ? AND estado != 'baja'`
    ).bind(limiteCadStr).all();
    if (matCad.results?.length) {
      const lineas = matCad.results.map(m => {
        const dias = Math.floor((new Date(m.fecha_caducidad) - hoy) / 86400000);
        return dias < 0
          ? `ГғВўГўвӮ¬Вә" ${m.codigo||m.nombre} (${m.tipo_material})${empLabel(m.empresa_id)} ГўвӮ¬вҖқ CADUCADO hace ${Math.abs(dias)} dГғВӯas`
          : `ГўЕЎВ ГҜВёВҸ ${m.codigo||m.nombre} (${m.tipo_material})${empLabel(m.empresa_id)} ГўвӮ¬вҖқ caduca en ${dias} dГғВӯas (${m.fecha_caducidad})`;
      });
      await sendTelegram(env, `Г°ЕёВҸВ·ГҜВёВҸ <b>Material Seguridad ГўвӮ¬вҖқ Caducidad prГғВіxima</b>\n\n` + lineas.join('\n'));
    }

    // 4. Carnets y certificaciones ГўвӮ¬вҖқ caducidad prГғВіxima o vencida
    const carnetsCad = await env.DB.prepare(
      `SELECT c.nombre_trabajador, c.tipo, c.fecha_caducidad, c.dias_aviso, c.usuario_id,
              c.empresa_id, u.telegram_id
       FROM carnets c LEFT JOIN usuarios u ON c.usuario_id = u.id
       WHERE c.fecha_caducidad IS NOT NULL AND c.fecha_caducidad != '' AND c.estado = 'vigente'`
    ).all();
    const carnetAlertas = [];
    for (const c of (carnetsCad.results || [])) {
      const dias = Math.floor((new Date(c.fecha_caducidad) - hoy) / 86400000);
      const aviso = c.dias_aviso || 30;
      let linea = null;
      if (dias < 0) linea = `ГғВўГўвӮ¬Вә" ${c.nombre_trabajador}${empLabel(c.empresa_id)} ГўвӮ¬вҖқ ${c.tipo} CADUCADO hace ${Math.abs(dias)} dГғВӯas`;
      else if (dias <= aviso) linea = `ГўЕЎВ ГҜВёВҸ ${c.nombre_trabajador}${empLabel(c.empresa_id)} ГўвӮ¬вҖқ ${c.tipo} caduca en ${dias} dГғВӯas (${c.fecha_caducidad})`;
      if (linea) {
        carnetAlertas.push(linea);
        // NotificaciГғВіn personal al trabajador si tiene Telegram vinculado
        if (c.telegram_id) {
          const msg = dias < 0
            ? `Г°ЕёвҖңЕ“ <b>Tu carnet ha caducado</b>\n\nTipo: ${c.tipo}\nCaducГғВі: ${c.fecha_caducidad}\n\nГўЕЎВ ГҜВёВҸ RenuГғВ©valo lo antes posible.`
            : `Г°ЕёвҖңЕ“ <b>Tu carnet caduca pronto</b>\n\nTipo: ${c.tipo}\nCaduca: ${c.fecha_caducidad} (<b>${dias} dГғВӯas</b>)\n\nRecuerda renovarlo a tiempo.`;
          await sendTelegramToChat(env, c.telegram_id, msg);
        }
      }
    }
    if (carnetAlertas.length) {
      await sendTelegram(env, `Г°ЕёвҖңЕ“ <b>Carnets y certificaciones ГўвӮ¬вҖқ Caducidad prГғВіxima</b>\n\n` + carnetAlertas.join('\n'));
    }

    // 5. Eventos del calendario ГўвӮ¬вҖқ hoy + recordatorios previos
    const hoyStr = hoy.toISOString().slice(0, 10);
    const { results: eventosHoy } = await env.DB.prepare(
      `SELECT e.titulo, e.hora, e.tipo, o.nombre as obra_nombre
       FROM eventos_calendario e LEFT JOIN obras o ON e.obra_id = o.id
       WHERE e.fecha = ? ORDER BY e.hora ASC`
    ).bind(hoyStr).all();
    if (eventosHoy.length) {
      const tipoIcon = { entrega:'Г°ЕёвҖңВҰ', revision:'Г°ЕёвҖңВ§', reunion:'Г°ЕёвҖҳВҘ', otro:'Г°ЕёвҖңвҖҰ' };
      const lineas = eventosHoy.map(ev =>
        `${tipoIcon[ev.tipo]||'Г°ЕёвҖңвҖҰ'} ${ev.titulo}${ev.hora ? ' ГўвӮ¬вҖқ ' + ev.hora : ''}${ev.obra_nombre ? ' [' + ev.obra_nombre + ']' : ''}`
      );
      await sendTelegram(env, `Г°ЕёвҖңвҖҰ <b>Eventos de hoy (${hoyStr})</b>\n\n` + lineas.join('\n'));
    }
    // Recordatorios anticipados (recordatorio_dias > 0)
    const { results: recordatorios } = await env.DB.prepare(`
      SELECT e.titulo, e.fecha, e.hora, e.tipo, e.recordatorio_dias, o.nombre as obra_nombre
      FROM eventos_calendario e LEFT JOIN obras o ON e.obra_id = o.id
      WHERE e.recordatorio_dias > 0 AND e.fecha > ?
    `).bind(hoyStr).all();
    for (const ev of recordatorios) {
      const diasFaltan = Math.floor((new Date(ev.fecha) - hoy) / 86400000);
      if (diasFaltan === ev.recordatorio_dias) {
        const tipoIcon = { entrega:'Г°ЕёвҖңВҰ', revision:'Г°ЕёвҖңВ§', reunion:'Г°ЕёвҖҳВҘ', otro:'Г°ЕёвҖңвҖҰ' };
        await sendTelegram(env,
          `ГғВўГғвҖҡГӮВҸГӮВ° <b>Recordatorio ГўвӮ¬вҖқ faltan ${diasFaltan} dГғВӯa${diasFaltan===1?'':'s'}</b>\n${tipoIcon[ev.tipo]||'Г°ЕёвҖңвҖҰ'} ${ev.titulo} (${ev.fecha}${ev.hora ? ' ' + ev.hora : ''})${ev.obra_nombre ? '\nГ°ЕёВҸвҖ” ' + ev.obra_nombre : ''}`
        );
      }
    }

    // ГўвҖқвӮ¬ГўвҖқвӮ¬ Tareas de obra vencidas ГўвӮ¬вҖқ alerta diaria por empresa ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬
    try {
      const hoyStr = hoy.toISOString().slice(0, 10);
      const { results: empresasConTareas } = await env.DB.prepare(
        `SELECT DISTINCT empresa_id FROM tareas_obra WHERE fecha_limite < ? AND estado NOT IN ('completada','bloqueada')`
      ).bind(hoyStr).all().catch(() => ({ results: [] }));

      for (const { empresa_id: eid } of (empresasConTareas || [])) {
        const { results: tareasVencidas } = await env.DB.prepare(
          `SELECT titulo, prioridad, asignado_a, fecha_limite FROM tareas_obra WHERE empresa_id=? AND fecha_limite < ? AND estado NOT IN ('completada','bloqueada') ORDER BY CASE prioridad WHEN 'urgente' THEN 0 WHEN 'alta' THEN 1 WHEN 'normal' THEN 2 ELSE 3 END LIMIT 10`
        ).bind(eid, hoyStr).all().catch(() => ({ results: [] }));

        if (tareasVencidas && tareasVencidas.length) {
          const priIcon = { urgente: 'Г°ЕёвҖқВҙ', alta: 'Г°ЕёЕёВ ', normal: 'Г°ЕёЕёВЎ', baja: 'Г°ЕёЕёВў' };
          let msg = `ГўЕЎВ ГҜВёВҸ <b>Tareas de obra vencidas</b> (${tareasVencidas.length}):\n\n`;
          for (const t of tareasVencidas) {
            msg += `${priIcon[t.prioridad] || 'ГўЕЎВӘ'} ${t.titulo}${t.asignado_a ? ' [' + t.asignado_a + ']' : ''} ГӮВ· vencГғВӯa ${t.fecha_limite}\n`;
          }
          await sendTelegram(env, msg);
        }
      }
    } catch(e) { console.error('tareas vencidas alert error:', e.message); }

    // ГўвҖқвӮ¬ГўвҖқвӮ¬ RFIs sin respuesta con fecha lГғВӯmite vencida ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬
    try {
      const hoyStr2 = hoy.toISOString().slice(0, 10);
      const { results: empresasConRfis } = await env.DB.prepare(
        `SELECT DISTINCT empresa_id FROM rfis WHERE fecha_limite < ? AND estado IN ('abierta','en_revision')`
      ).bind(hoyStr2).all().catch(() => ({ results: [] }));

      for (const { empresa_id: eid } of (empresasConRfis || [])) {
        const { results: rfisVencidas } = await env.DB.prepare(
          `SELECT numero, titulo, prioridad, asignado_a, fecha_limite FROM rfis WHERE empresa_id=? AND fecha_limite < ? AND estado IN ('abierta','en_revision') ORDER BY CASE prioridad WHEN 'urgente' THEN 0 WHEN 'alta' THEN 1 WHEN 'normal' THEN 2 ELSE 3 END LIMIT 8`
        ).bind(eid, hoyStr2).all().catch(() => ({ results: [] }));

        if (rfisVencidas && rfisVencidas.length) {
          const priIcon = { urgente: 'Г°ЕёвҖқВҙ', alta: 'Г°ЕёЕёВ ', normal: 'Г°ЕёЕёВЎ', baja: 'Г°ЕёЕёВў' };
          let msg = `Г°ЕёвҖңвҖ№ <b>RFIs sin respuesta vencidas</b> (${rfisVencidas.length}):\n\n`;
          for (const r of rfisVencidas) {
            msg += `${priIcon[r.prioridad] || 'ГўЕЎВӘ'} ${r.numero||'RFI'} ${r.titulo}${r.asignado_a ? ' ГўвҖ вҖҷ ' + r.asignado_a : ''} ГӮВ· lГғВӯmite ${r.fecha_limite}\n`;
          }
          await sendTelegram(env, msg);
        }
      }
    } catch(e) { console.error('rfis vencidas alert error:', e.message); }

    // ГўвҖқвӮ¬ГўвҖқвӮ¬ Deficiencias urgentes abiertas sin resolver ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬
    try {
      const hoyStr3 = hoy.toISOString().slice(0, 10);
      const { results: empresasConDef } = await env.DB.prepare(
        `SELECT DISTINCT empresa_id FROM control_calidad WHERE estado IN ('abierto','en_reparacion') AND (prioridad='urgente' OR (fecha_limite IS NOT NULL AND fecha_limite < ?))`
      ).bind(hoyStr3).all().catch(() => ({ results: [] }));

      for (const { empresa_id: eid } of (empresasConDef || [])) {
        const { results: defsAbiertas } = await env.DB.prepare(
          `SELECT numero, titulo, prioridad, ubicacion, fecha_limite FROM control_calidad WHERE empresa_id=? AND estado IN ('abierto','en_reparacion') AND (prioridad='urgente' OR (fecha_limite IS NOT NULL AND fecha_limite < ?)) ORDER BY CASE prioridad WHEN 'urgente' THEN 0 WHEN 'alta' THEN 1 WHEN 'normal' THEN 2 ELSE 3 END LIMIT 8`
        ).bind(eid, hoyStr3).all().catch(() => ({ results: [] }));

        if (defsAbiertas && defsAbiertas.length) {
          const priIcon = { urgente: 'Г°ЕёвҖқВҙ', alta: 'Г°ЕёЕёВ ', normal: 'Г°ЕёЕёВЎ', baja: 'Г°ЕёЕёВў' };
          let msg = `Г°ЕёвҖқВҚ <b>Deficiencias urgentes / vencidas sin resolver</b> (${defsAbiertas.length}):\n\n`;
          for (const d of defsAbiertas) {
            msg += `${priIcon[d.prioridad] || 'ГўЕЎВӘ'} ${d.numero||'DEF'} ${d.titulo}${d.ubicacion ? ' Г°ЕёвҖңВҚ' + d.ubicacion : ''}${d.fecha_limite ? ' ГӮВ· lГғВӯmite ' + d.fecha_limite : ''}\n`;
          }
          await sendTelegram(env, msg);
        }
      }
    } catch(e) { console.error('deficiencias alert error:', e.message); }

    // Subcontratas ГўвӮ¬вҖқ seguros y habilitaciones que vencen en 30 dГғВӯas
    try {
      const en30s = new Date(Date.now() + 30*86400000).toISOString().slice(0,10);
      const hoyStr4 = hoy.toISOString().slice(0,10);
      const { results: subcVencen } = await env.DB.prepare(
        `SELECT s.empresa_id, s.nombre, s.seguro_rc_expiry, s.habilitacion_expiry
         FROM subcontratas s
         WHERE s.estado='activa' AND (
           (s.seguro_rc_expiry IS NOT NULL AND s.seguro_rc_expiry BETWEEN ? AND ?) OR
           (s.habilitacion_expiry IS NOT NULL AND s.habilitacion_expiry BETWEEN ? AND ?)
         ) ORDER BY s.empresa_id, COALESCE(s.seguro_rc_expiry,s.habilitacion_expiry)`
      ).bind(hoyStr4, en30s, hoyStr4, en30s).all().catch(()=>({results:[]}));
      if (subcVencen && subcVencen.length) {
        const porEmpSub = {};
        for (const s of subcVencen) {
          if (!porEmpSub[s.empresa_id]) porEmpSub[s.empresa_id] = [];
          porEmpSub[s.empresa_id].push(s);
        }
        for (const [eid, subcs] of Object.entries(porEmpSub)) {
          let msg = `Г°ЕёВҸВў <b>Certificaciones de subcontratas por vencer</b>${empLabel(parseInt(eid))} (${subcs.length}):\n\n`;
          for (const s of subcs) {
            if (s.seguro_rc_expiry && s.seguro_rc_expiry <= en30s)
              msg += `ГўЕЎВ ГҜВёВҸ <b>${s.nombre}</b> ГўвӮ¬вҖқ Seguro RC vence: ${s.seguro_rc_expiry}\n`;
            if (s.habilitacion_expiry && s.habilitacion_expiry <= en30s)
              msg += `ГўЕЎВ ГҜВёВҸ <b>${s.nombre}</b> ГўвӮ¬вҖқ HabilitaciГғВіn vence: ${s.habilitacion_expiry}\n`;
          }
          await sendTelegram(env, msg);
        }
      }
    } catch(e) { console.error('subcontratas cert alert error:', e.message); }

    // Hitos de obra ГўвӮ¬вҖқ alertar sobre hitos que vencen en alertar_dias dГғВӯas
    try {
      const hoyStr5 = hoy.toISOString().slice(0, 10);
      const { results: hitosProximos } = await env.DB.prepare(
        `SELECT h.empresa_id, h.obra_id, h.nombre, h.fecha, h.tipo, h.responsable, h.alertar_dias,
                o.nombre as obra_nombre
         FROM hitos_obra h
         LEFT JOIN obras o ON h.obra_id = o.id
         WHERE h.estado = 'pendiente'
           AND h.fecha BETWEEN ? AND date(?, '+' || h.alertar_dias || ' days')
         ORDER BY h.empresa_id, h.fecha`
      ).bind(hoyStr5, hoyStr5).all().catch(() => ({ results: [] }));
      if (hitosProximos && hitosProximos.length) {
        // Group by empresa
        const byEmp = {};
        for (const h of hitosProximos) {
          if (!byEmp[h.empresa_id]) byEmp[h.empresa_id] = [];
          byEmp[h.empresa_id].push(h);
        }
        for (const [eid, items] of Object.entries(byEmp)) {
          const diasHasta = (fecha) => Math.ceil((new Date(fecha) - hoy) / 86400000);
          let msg = `Г°ЕёВҸВҒ *Hitos prГғВіximos de obra*\n\n`;
          for (const h of items) {
            const d = diasHasta(h.fecha);
            const cuando = d === 0 ? 'ГӮВЎHOY!' : d === 1 ? 'maГғВұana' : `en ${d} dГғВӯas`;
            msg += `ГўвӮ¬Вў *${h.obra_nombre || `Obra ${h.obra_id}`}*: ${h.nombre} (${cuando}, ${h.fecha})\n`;
            if (h.responsable) msg += `  Г°ЕёвҖҳВӨ ${h.responsable}\n`;
          }
          await sendTelegram(env, msg, parseInt(eid));
        }
      }
    } catch(e) { console.error('hitos obra alert error:', e.message); }

    // RGPD ГўвӮ¬вҖқ aplicar retenciГғВіn automГғВЎtica a todas las empresas que la tengan activa
    try {
      const { results: empresasRgpd } = await env.DB.prepare(
        `SELECT id FROM empresas WHERE activa=1 AND retencion_config IS NOT NULL`
      ).all().catch(() => ({ results: [] }));
      for (const emp of (empresasRgpd || [])) {
        await rgpdAplicarRetencion(env, emp.id);
      }
    } catch(e) { console.error('rgpd retencion cron error:', e.message); }

  } catch(e) {
    console.error('alertasDiarias error:', e.message);
  }
}

